-- Templates : message de l'humain À LA tortue du contact, pour son anniversaire
-- animal_type = 'tortue' | animal_direction = 'to' | occasion = 'birthday'

insert into public.message_templates
  (user_id, title, content, tone, is_system, is_manual_only, occasion, animal_type, animal_direction)
values

(null, 'Joyeux anniversaire sage créature.',
$$"Joyeux anniversaire sage créature." Ton humain m'a dit quel âge tu avais. J'ai recalculé trois fois parce que je croyais pas. T'as vécu des choses que j'imagine même pas. Des époques. Des modes. Des présidents. Des technologies. Et te voilà là. Tranquille. Imperturbable. Joyeux anniversaire, survivant(e) de l'histoire moderne.
Avec respect profond et complexe d'infériorité temporelle, Celui/celle qui a trois fois moins vécu que toi 📜$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'On s''est rencontrés il y a longtemps.',
$$"On s'est rencontrés il y a longtemps." T'étais déjà là avant que je connaisse ton humain. T'étais là quand on s'est rencontrés. T'es là maintenant. T'as vu notre amitié naître et grandir depuis ton coin. T'es le témoin le plus ancien de notre histoire. Joyeux anniversaire, archiviste vivant(e) de nos vies.
Avec gratitude pour ta continuité rassurante, Celui/celle que tu observes depuis le début 🏛️$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'Ton humain m''a dit que tu reconnaissais les gens.',
$$"Ton humain m'a dit que tu reconnaissais les gens." Que t'avais ta façon de réagir différemment selon les personnes. Que tu savais qui t'aimait vraiment. Que tu te souvenais. Que tu évaluais. Que ton verdict était définitif. J'espère que j'ai eu la bonne note. Joyeux anniversaire, juge implacable à la mémoire longue.
Avec comportement exemplaire maintenu depuis notre première rencontre, Celui/celle qui essaie de rester dans tes bonnes grâces ⚖️$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'J''ai essayé de trouver un cadeau adapté à une tortue.',
$$"J'ai essayé de trouver un cadeau adapté à une tortue." Internet m'a proposé des cachettes. Des lampes chauffantes. Des légumes spéciaux. Des pierres plates pour se reposer. J'ai pris la pierre. Elle est belle. Plate. Parfaite. Ton humain dit que tu vas l'ignorer pendant trois semaines puis l'adopter définitivement. J'attends. Joyeux anniversaire, être aux adoptions lentes et définitives.
Avec patience infinie et pierre déposée sans pression, Ton fournisseur officiel de pierres plates en attente de validation 🪨$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'T''avances lentement. Mais t''avances.',
$$"T'avances lentement. Mais t'avances." Je t'ai observé(e) traverser le salon une fois. Ça a pris du temps. T'as pas dévié. T'as pas accéléré. T'as pas regardé si on te regardait. T'avais un but. T'es arrivé(e). C'était la leçon de management la plus efficace que j'aie jamais reçue. Joyeux anniversaire, consultant(e) en efficacité à taux horaire lent mais rentable.
Avec leçon appliquée dès le lendemain au bureau, Ton élève en développement personnel involontaire 📈$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'Ton humain te parle différemment qu''aux autres animaux.',
$$"Ton humain te parle différemment qu'aux autres animaux." Lentement. Calmement. Comme si il/elle adaptait son rythme au tien. Comme si ta sérénité était contagieuse. J'ai essayé de faire pareil. Ça m'a pris dix minutes pour dire bonjour. C'était la conversation la plus apaisante de ma semaine. Joyeux anniversaire, régulateur(régulatrice) de rythme humain.
Avec débit verbal ralenti et tension artérielle améliorée, Celui/celle que t'as appris(e) à souffler 🌬️$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'J''ai regardé des documentaires sur les tortues pour préparer cette visite.',
$$"J'ai regardé des documentaires sur les tortues pour préparer cette visite." T'avez vécu avec les dinosaures. T'avez survécu à des extinctions. T'avez traversé des millions d'années sans changer de design parce que le design était parfait dès le début. Je me sens très jeune et très provisoire à côté de toi. Joyeux anniversaire, chef d'œuvre évolutif intemporel.
Avec humilité géologique et admiration sincère, Celui/celle que l'évolution a moins bien réussi 🦕$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'T''as une carapace qui te protège de tout.',
$$"T'as une carapace qui te protège de tout." Les chocs. Le froid. Le regard des autres. Les mauvais jours. J'ai pas ça moi. Je prends tout en pleine face. Parfois j'aimerais juste pouvoir rentrer dedans cinq minutes et attendre que ça passe. T'as inventé la meilleure solution du monde. Joyeux anniversaire, ingénieur(ingénieure) de génie de la protection personnelle.
Avec envie profonde de ta carapace les lundis matin, Celui/celle qui commande la sienne sur internet depuis des années 🛡️$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'Ton humain prend soin de toi avec une régularité qui force le respect.',
$$"Ton humain prend soin de toi avec une régularité qui force le respect." Chaque jour. Même rythme. Même attention. Même amour tranquille. Vous avez trouvé votre tempo ensemble. Lent. Stable. Durable. C'est la relation la plus solide que je connaisse. Joyeux anniversaire, partenaire d'une histoire qui s'inscrit dans le temps long.
Avec admiration pour votre rythme commun parfaitement accordé, Le/la témoin de votre belle lenteur partagée 🤝$$,
'humorous', true, false, 'birthday', 'tortue', 'to'),

(null, 'Je sais pas combien d''anniversaires tu vas encore avoir.',
$$"Je sais pas combien d'anniversaires tu vas encore avoir." Beaucoup probablement. Plus que moi peut-être. Et à chacun je veux être là. Parce que t'es devenu(e) important(e) sans que je m'en rende compte. Comme les choses lentes et solides le font. Progressivement. Définitivement. Joyeux anniversaire, présence discrète devenue indispensable.
Avec attachement tardif mais total, Celui/celle que t'as conquis(e) à ton rythme, c'est à dire lentement et pour toujours 🐢❤️$$,
'humorous', true, false, 'birthday', 'tortue', 'to');
